export type RequestCustom = RequestInit & {
    url: string;
    headers?: Headers;
    authorizedRequest?: boolean;
    consumerKey?: string;
    rawResponse?: boolean;
    signal?: AbortSignal | null;
};
/**
 * @description HTTP request client to facilitate API call.

 * @param url request url </br>
 * @param method HTTP verb defaults to 'GET'
 * @param body the request body
 * @param headers the HTTP headers. Few default values are set
 *
 * `Accept` -> `application/json`
 *
 *
 * `Content-Type` -> `application/json` if the method is one of `PUT`, `POST` or `PATCH` and `body` is set
 * @param credentials controls what browsers do with credentials
 * @param authorizedRequest if the `Authorization` header should be set, defaults to `true`. The token is retrieved by `getJwt` method from this library
 * @param consumerKey if the `consumerKey` is set, additional `Consumer-Key` header will be set with the provided value
 * @param rawResponse if set to `true`, this function will return the raw fetch response, defaults to `false`
 * @param signal allows to cancel pending API request, defaults to 'undefined'
 *
 * @returns one of:
 *
 * `rawResponse` is set to `true` -> the raw fetch response
 *
 * `response` is `204` -> `undefined`
 *
 * `response` has `Content-Type` header set to the default one -> JSON representation of the payload
 *
 * `response` has `Content-Type` header set to value different than default one -> `response.body`
 */
export declare function executeRequest<T>(requestCustom: RequestCustom): Promise<T>;
